module top_module(
    input clk,
    input reset,    
    input j,
    input k,
    output out);parameter OFF=0, ON=1; 
    reg alt_state, next_state;

    always @(*) begin

        case(alt_state)
            OFF: next_state = (j)? ON:OFF;
            ON: next_state = (k)? OFF:ON;
        endcase
    end

    always @(posedge clk) begin

        if (reset)
            alt_state <= OFF;
        else
            alt_state <= next_state;
    end


    assign out = (alt_state == ON);

endmodule
